const KEY = 'tickmark';     //* minorticks
export function radial_minorticks_position() {
    const position = this.helpers.position;

    const { commonOption, data } = this,
        { tickConstants, tickmarkStart, tickSizeInner } = commonOption,
        { k, l, m, x, w, y, h } = tickConstants;

    position[KEY] = {
        attrs_key: { x, w, y },
        [`${x}1`]: k * tickmarkStart,
        [`${x}2`]: k * tickmarkStart + m * tickSizeInner
    };
}

export function radial_minorticks_styles() {
    const { data, helpers } = this,
        { styles } = helpers,
        { tickmark } = data;

    styles[KEY] = {
        strokeWidth: tickmark.strokeWidth,
        fill: 'none',
        shapeRendering: 'crispedges',
        stroke: tickmark.color
    }
}